function record_decision(request_id, step_id, rationale, action):
    entry = {
        request_id: request_id,
        step_id: step_id,
        ts: now(),
        rationale: rationale,        # chain-of-thought or summary
        action: action,              # what the agent then did
    }
    decision_log.append(entry)       # append-only store
    return entry.id

function step(state, request_id):
    thought = agent.deliberate(state)
    action  = agent.pick_action(thought)
    record_decision(request_id, state.step_id, thought, action)
    return execute(action)

