@action(reads=["question"], writes=["rationale", "action"])
def deliberate(state: State) -> State:
    thought = llm.think(state["question"])      # chain-of-thought
    return state.update(rationale=thought.text, action=thought.next_action)


@action(reads=["action"], writes=["result"])
def execute(state: State) -> State:
    return state.update(result=run_tool(state["action"]))


