    .with_transitions(("deliberate", "execute"))
    .with_entrypoint("deliberate")
    .with_state(question="summarise the deal")
    .with_tracker(tracker)            # rationale + action both indexed
    .with_identifiers(app_id="req-987")
    .build()
)
app.run(halt_after=["execute"])

