@action(reads=["question"], writes=["docs", "retrieved_ids"])
def retrieve(state: State) -> State:
    docs = retriever.search(state["question"])
    return state.update(docs=docs, retrieved_ids=[d.id for d in docs])


@action(reads=["question", "docs"], writes=["answer", "lineage"])
def answer(state: State, prompt_tpl: str, model: str) -> State:
    prompt = prompt_tpl.format(q=state["question"], docs=state["docs"])
    resp = llm.complete(prompt, model=model)
    return state.update(
        answer=resp.text,
        lineage={
            "prompt_hash": sha256(prompt_tpl.encode()).hexdigest(),
            "model": model,
            "retrieved_ids": state["retrieved_ids"],
        },
    )


app = (
    ApplicationBuilder()
    .with_actions(retrieve, answer)
    .with_transitions(("retrieve", "answer"))
