RUBRIC = [
    {name: "correctness",  scale: 1..5},
    {name: "completeness", scale: 1..5},
    {name: "faithfulness", scale: 1..5},
]

function llm_judge(input, output, rubric=RUBRIC):
    prompt = render(JUDGE_TEMPLATE, input=input, output=output, rubric=rubric)
    verdict = judge_model.generate(           # different family vs candidate
        prompt,
        response_format=schema_of(rubric + ["rationale"]),
    )
    return parse(verdict)

function calibrate(judge, human_graded_samples, threshold=0.8):
    scores = [llm_judge(s.input, s.output) for s in human_graded_samples]
    rho = correlation(scores, [s.human_score for s in human_graded_samples])
    if rho < threshold:
        alert("judge drifted; retune rubric or swap model")
    return rho

# Registry semantics — backing store can be filesystem, S3, db, etc.
function register(name, semver, source):
    artefact = {
        name:    name,
        version: semver,             # "1.4.0"
        hash:    sha256(source),
        source:  source,
        signed:  sign(source, key),  # optional provenance
        created_at: now(),
    }
    if registry.exists(name, semver):
        raise Immutable(name, semver)   # versions never change
    registry.put(name, semver, artefact)
    return artefact

function get(name, semver):
    return registry.get(name, semver)

