REQUIRED_FIELDS = ["ts", "actor", "action", "target",
                   "justification", "diff_hash"]

function append_event(event):
    for f in REQUIRED_FIELDS:
        if f not in event:
            raise IncompleteEvent(missing=f)
    event.id = monotonic_id()
    ledger.append_immutable(event)         # append-only store
    return event.id

function rollback(event_id):
    event = ledger.get(event_id)
    inverse = compute_inverse(event)       # uses diff_hash + target
    return append_event({
        ts: now(),
        actor: "system:rollback",
        action: inverse.action,
        target: event.target,
        justification: f"rollback of {event_id}",
        diff_hash: inverse.diff_hash,
    })

from operator import add
from typing import Annotated
from typing_extensions import TypedDict
from langgraph.graph import StateGraph, START, END
from langgraph.checkpoint.memory import InMemorySaver


class S(TypedDict):
    foo: str
    bar: Annotated[list[str], add]


def node_a(state: S):
    return {"foo": "a", "bar": ["a"]}


def node_b(state: S):
    return {"foo": "b", "bar": ["b"]}


g = StateGraph(S)
g.add_node(node_a); g.add_node(node_b)
g.add_edge(START, "node_a"); g.add_edge("node_a", "node_b"); g.add_edge("node_b", END)
graph = g.compile(checkpointer=InMemorySaver())

cfg = {"configurable": {"thread_id": "t-1"}}
graph.invoke({"foo": "", "bar": []}, cfg)

# Time-travel: list checkpoints, pick one before node_b, replay forward.
history = list(graph.get_state_history(cfg))
before_b = next(s for s in history if s.next == ("node_b",))

branch_cfg = {
    "configurable": {
        "thread_id": "t-1",
        "checkpoint_id": before_b.config["configurable"]["checkpoint_id"],
    }
}
graph.invoke(None, branch_cfg)        # re-runs node_b only

ALLOWED_SYSCALLS = {"read", "write", "openat", "close", "stat"}
EGRESS_ALLOWLIST = {"api.openai.com", "127.0.0.1"}
WORKDIR          = "/sandbox/agent-42"

function on_syscall(event):
    if event.name not in ALLOWED_SYSCALLS:
        emit("sandbox.escape", {kind: "syscall", event: event})
        breach_counter.inc()

function on_network(event):
    if event.host not in EGRESS_ALLOWLIST:
        emit("sandbox.escape", {kind: "egress", event: event})
        breach_counter.inc()

function on_fs_write(event):
    if not event.path.starts_with(WORKDIR):
        emit("sandbox.escape", {kind: "fs_write", event: event})
        breach_counter.inc()

