function scorer_worker(scorers):
    for msg in scoring_stream.consume():
        for s in scorers:                 # judge LLM, regex, embedding-sim, ...
            score = s.score(msg.input, msg.output, msg.context)
            score_store.write({
                request_id: msg.request_id,
                scorer:     s.name,
                score:      score.value,
                evidence:   score.evidence,
            })
            if score.value < s.low_threshold:
                review_queue.enqueue(msg.request_id)  # NOT regenerate

function handle_request(request, champion, challenger, sample_rate=0.05):
    champ_out = champion.run(request.input)
    respond(request, champ_out)              # user sees ONLY champion

    if rand() < sample_rate:
        # run shadow off the user's critical path
        spawn(async () -> {
            chall_out = challenger.run(request.input)
            diff = {
                request_id: request.id,
                judge_score: llm_judge(request.input, chall_out, champ_out),
                tool_match:  champ_out.tool_calls == chall_out.tool_calls,
                latency_d:   chall_out.latency - champ_out.latency,
                cost_d:      chall_out.cost    - champ_out.cost,
            }
            shadow_metrics.write(diff)
        })

function promotion_decision(window):
    m = shadow_metrics.aggregate(window)
    return "promote" if m.judge_lift > 0 and m.cost_d <= 0 else "hold"
